    for (x in 0..MAX_VAL) {
        val d = sumDigits(x.toLong())
        if (d <= MAX_D) {
            C[d].add(x)
        }
    }

    val N = digitSum.size

    // DP arrays: dp[x] stores the number of valid sequences ending at x.
    // We use two arrays to alternate between previous and current states.
    var dpPrev = IntArray(MAX_VAL + 1)
    var dpCurr = IntArray(MAX_VAL + 1)

    // 2. Initialization (i=0)
