    if (d0 <= MAX_D) {
        for (x in C[d0]) {
            dpPrev[x] = 1
        }
    } else {
        // If the first required digit sum is out of range, the answer is 0.
        return 0L
    }

    // 3. Iteration (i=1 to N-1)
    for (i in 1 until N) {
        val dCurr = digitSum[i].toInt()

        // Reset current DP array
        dpCurr.fill(0)

